'use client'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { saveSession } from '@/lib/eso-auth'

export default function RegisterPage() {
  const router = useRouter()
  const [email,    setEmail]    = useState('')
  const [username, setUsername] = useState('')
  const [password, setPassword] = useState('')
  const [confirm,  setConfirm]  = useState('')
  const [error,    setError]    = useState('')
  const [loading,  setLoading]  = useState(false)

  // NO auto-redirect — user navigated here intentionally

  async function submit(e: React.FormEvent) {
    e.preventDefault()
    if (password !== confirm) { setError('Passwords do not match'); return }
    if (password.length < 8)  { setError('Password must be at least 8 characters'); return }
    setLoading(true); setError('')
    try {
      const res = await fetch('/api/eso/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, username, password }),
      })
      const d = await res.json()
      if (!res.ok) throw new Error(d.detail || 'Registration failed')
      saveSession(d.access_token, d.user)
      router.push('/scan')
    } catch (e: any) {
      setError(e.message)
    } finally {
      setLoading(false)
    }
  }

  const inp = "w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-4 py-3 font-mono text-[13px] text-slate-200 outline-none focus:border-accent/50 transition-all placeholder-slate-700"

  return (
    <div className="min-h-screen flex items-center justify-center p-5" style={{ background:'#03050a' }}>
      <div className="w-full max-w-[380px]">
        <div className="text-center mb-10">
          <Link href="/dashboard">
            <div className="inline-flex items-center gap-2 mb-3">
              <div className="w-10 h-10 rounded-xl flex items-center justify-center text-xl"
                style={{ background:'linear-gradient(135deg,#00ffaa22,#00aaff22)', border:'1px solid rgba(0,255,170,0.2)' }}>🛡</div>
              <span className="text-2xl font-black">X<span style={{ color:'#00ffaa' }}>cloak</span></span>
            </div>
          </Link>
          <p className="font-mono text-[11px] text-slate-600">Create your free account</p>
        </div>

        <div className="glass p-6">
          <form onSubmit={submit} className="space-y-4">
            <div className="space-y-1">
              <label className="font-mono text-[9px] uppercase tracking-widest text-slate-600">Email</label>
              <input type="email" required value={email} onChange={e => setEmail(e.target.value)}
                placeholder="you@example.com" className={inp} autoFocus />
            </div>
            <div className="space-y-1">
              <label className="font-mono text-[9px] uppercase tracking-widest text-slate-600">Username</label>
              <input type="text" required minLength={3} value={username} onChange={e => setUsername(e.target.value)}
                placeholder="0xhacker" className={inp} />
            </div>
            <div className="space-y-1">
              <label className="font-mono text-[9px] uppercase tracking-widest text-slate-600">Password</label>
              <input type="password" required value={password} onChange={e => setPassword(e.target.value)}
                placeholder="Min 8 characters" className={inp} />
            </div>
            <div className="space-y-1">
              <label className="font-mono text-[9px] uppercase tracking-widest text-slate-600">Confirm Password</label>
              <input type="password" required value={confirm} onChange={e => setConfirm(e.target.value)}
                placeholder="••••••••" className={inp} />
            </div>

            <div className="p-3 rounded-xl border border-white/[0.06] bg-white/[0.02]">
              <div className="font-mono text-[9px] uppercase tracking-widest text-slate-700 mb-2">Free tier includes</div>
              {['3 scans/day · nmap scanner', 'CVE tracker, exploits, CTF community', 'Scan history & reports', 'Upgrade anytime for more tools'].map(f => (
                <div key={f} className="flex items-center gap-2 py-0.5">
                  <span className="text-accent text-[8px]">✓</span>
                  <span className="font-mono text-[10px] text-slate-600">{f}</span>
                </div>
              ))}
            </div>

            {error && (
              <div className="font-mono text-[11px] text-red-400 p-3 rounded-xl border border-red-500/20 bg-red-500/[0.05]">
                ✗ {error}
              </div>
            )}

            <button type="submit" disabled={loading}
              className="w-full py-3 rounded-xl font-mono text-[13px] font-bold cursor-pointer transition-all disabled:opacity-40"
              style={{ background:'linear-gradient(135deg,rgba(0,255,170,0.15),rgba(0,170,255,0.1))', border:'1px solid rgba(0,255,170,0.3)', color:'#00ffaa' }}>
              {loading ? '⟳ Creating account...' : 'Create Free Account →'}
            </button>
          </form>

          <div className="mt-5 pt-5 border-t border-white/[0.06] text-center space-y-2">
            <p className="font-mono text-[11px] text-slate-600">
              Already have an account? <Link href="/login" className="text-accent hover:underline">Sign in</Link>
            </p>
            <p className="font-mono text-[10px] text-slate-700">
              By registering you agree to our{' '}
              <Link href="/terms" className="text-slate-500 hover:text-slate-300 transition-colors">Terms of Service</Link>
              {' '}and{' '}
              <Link href="/privacy" className="text-slate-500 hover:text-slate-300 transition-colors">Privacy Policy</Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  )
}
